BEGIN; ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS avatar_url text; CREATE OR REPLACE FUNCTION public.update_own_avatar_url(p_avatar_url text) RETURNS text LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ DECLARE v_user_id uuid := auth.uid(); v_clean_url text := NULLIF(btrim(p_avatar_url), ''); BEGIN IF v_user_id IS NULL THEN RAISE EXCEPTION 'Ban can dang nhap de cap nhat anh dai dien.'; END IF; IF v_clean_url IS NOT NULL AND v_clean_url !~ '^https?://[^[:space:]]+$' THEN RAISE EXCEPTION 'Link anh dai dien khong hop le.'; END IF; UPDATE public.profiles SET avatar_url = v_clean_url WHERE id = v_user_id AND deleted_at IS NULL AND COALESCE(is_active, false) = true AND COALESCE(is_approved, false) = true; IF NOT FOUND THEN RAISE EXCEPTION 'Tai khoan khong du dieu kien cap nhat anh dai dien.'; END IF; RETURN v_clean_url; END; $$; REVOKE ALL ON FUNCTION public.update_own_avatar_url(text) FROM PUBLIC, anon; GRANT EXECUTE ON FUNCTION public.update_own_avatar_url(text) TO authenticated; INSERT INTO storage.buckets (id, name, public, file_size_limit, allowed_mime_types) VALUES ('profile-avatars', 'profile-avatars', true, 2097152, ARRAY['image/jpeg', 'image/png', 'image/webp']) ON CONFLICT (id) DO UPDATE SET public = true, file_size_limit = 2097152, allowed_mime_types = ARRAY['image/jpeg', 'image/png', 'image/webp']; DROP POLICY IF EXISTS "profile_avatars_public_select" ON storage.objects; CREATE POLICY "profile_avatars_public_select" ON storage.objects FOR SELECT TO public USING (bucket_id = 'profile-avatars'); DROP POLICY IF EXISTS "profile_avatars_own_insert" ON storage.objects; CREATE POLICY "profile_avatars_own_insert" ON storage.objects FOR INSERT TO authenticated WITH CHECK (bucket_id = 'profile-avatars' AND auth.uid()::text = (storage.foldername(name))[1]); DROP POLICY IF EXISTS "profile_avatars_own_update" ON storage.objects; CREATE POLICY "profile_avatars_own_update" ON storage.objects FOR UPDATE TO authenticated USING (bucket_id = 'profile-avatars' AND auth.uid()::text = (storage.foldername(name))[1]) WITH CHECK (bucket_id = 'profile-avatars' AND auth.uid()::text = (storage.foldername(name))[1]); NOTIFY pgrst, 'reload schema'; COMMIT;
